package com.example.gr01_1bt3_622_26a.entity;

import jakarta.persistence.*;
import jakarta.validation.constraints.*;
import lombok.*;
import java.time.LocalDate;
import java.time.LocalDateTime;

/**
 *  REFACTOR: Entidad Usuario COMPLETA con JPA y Validaciones
 * 
 * Ciclo TDD:
 *  RED: Test falla (Usuario no existe)
 *  GREEN: Se crea Usuario mínimo
 *  REFACTOR: Se mejora con validaciones, JPA, campos adicionales
 */
@Entity
@Table(name = "usuarios", uniqueConstraints = {
        @UniqueConstraint(columnNames = "email"),
        @UniqueConstraint(columnNames = "documento_identidad")
})
@Data
@NoArgsConstructor
@AllArgsConstructor
@Builder
public class Usuario {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @NotBlank(message = "El email es requerido")
    @Email(message = "El email debe ser válido")
    @Column(nullable = false, unique = true)
    private String email;

    @NotBlank(message = "La contraseña es requerida")
    @Size(min = 6, message = "La contraseña debe tener al menos 6 caracteres")
    @Column(nullable = false)
    private String password;

    @NotBlank(message = "El nombre es requerido")
    @Size(min = 2, max = 100, message = "El nombre debe tener entre 2 y 100 caracteres")
    @Column(nullable = false)
    private String nombre;

    @Column(nullable = false)
    @Builder.Default
    private String estado = "ACTIVO"; // ACTIVO, INACTIVO, BLOQUEADO

    @Enumerated(EnumType.STRING)
    @Column(nullable = false)
    @Builder.Default
    private RolUsuario rol = RolUsuario.SOLICITANTE;

    @Column(name = "documento_identidad", unique = true)
    private String documentoIdentidad;

    @Column(name = "fecha_creacion")
    private LocalDate fechaCreacion;

    @Column(name = "fecha_ultimo_login")
    private LocalDateTime fechaUltimoLogin;

    @Column(name = "token_recuperacion")
    private String tokenRecuperacion;

    @Column(name = "fecha_expiracion_token")
    private LocalDate fechaExpiracionToken;

    @Column(name = "intentos_fallidos", columnDefinition = "int default 0")
    @Builder.Default
    private Integer intentosFallidos = 0;

    @PrePersist
    protected void onCreate() {
        if (fechaCreacion == null) {
            fechaCreacion = LocalDate.now();
        }
        if (estado == null) {
            estado = "ACTIVO";
        }
        if (rol == null) {
            rol = RolUsuario.SOLICITANTE;
        }
    }

    /**
     * Enumeración de roles disponibles en el sistema
     */
    public enum RolUsuario {
        ADMIN("Administrador"),
        SOLICITANTE("Solicitante de Adopción"),
        STAFF("Personal del Sistema");

        private final String descripcion;

        RolUsuario(String descripcion) {
            this.descripcion = descripcion;
        }

        public String getDescripcion() {
            return descripcion;
        }
    }

    /**
     * Métodos de negocio para validación
     */
    public boolean esActivo() {
        return "ACTIVO".equals(this.estado);
    }

    public boolean estaAlimentado() {
        return intentosFallidos < 3;
    }

    public void incrementarIntentosFallidos() {
        this.intentosFallidos++;
        if (this.intentosFallidos >= 3) {
            this.estado = "BLOQUEADO";
        }
    }

    public void reiniciarIntentosFallidos() {
        this.intentosFallidos = 0;
    }

    public void registrarUltimoLogin() {
        this.fechaUltimoLogin = LocalDateTime.now();
        this.reiniciarIntentosFallidos();
    }
}

package com.example.gr01_1bt3_622_26a.service;

import com.example.gr01_1bt3_622_26a.entity.Usuario;
import com.example.gr01_1bt3_622_26a.repository.UsuarioRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import java.time.LocalDate;

/**
 *  REFACTOR: UsuarioService MEJORADO
 *
 * Ciclo TDD:
 *  RED: Test falla (no existe UsuarioService)
 *  GREEN: Se crea UsuarioService mínimo
 *  REFACTOR: Se mejora con validaciones, excepciones, logging
 *
 * Responsabilidades:
 * - Registrar nuevos usuarios
 * - Validar datos de entrada
 * - Manejo de excepciones
 * - Logging de eventos
 */
@Service
@RequiredArgsConstructor
@Slf4j
public class UsuarioService {

    private final UsuarioRepository usuarioRepository;

    /**
     * Registrar un nuevo usuario en la base de datos
     *
     * @param email Email del usuario
     * @param password Contraseña
     * @param nombre Nombre completo
     * @return Usuario registrado con ID asignado
     * @throws IllegalArgumentException si email ya existe o datos inválidos
     */
    public Usuario registrarUsuario(String email, String password, String nombre) {
        log.info(" [REGISTRO] Iniciando registro de usuario: {}", email);

        // Validaciones
        validarEmail(email);
        validarPassword(password);
        validarNombre(nombre);

        // Verificar que el email no exista
        if (usuarioRepository.existsByEmail(email)) {
            log.warn("⚠️ [REGISTRO] Email ya registrado: {}", email);
            throw new IllegalArgumentException("El email " + email + " ya está registrado");
        }

        // Crear usuario
        Usuario usuario = Usuario.builder()
                .email(email)
                .password(password) //  REFACTOR: En producción encriptar con BCrypt
                .nombre(nombre)
                .estado("ACTIVO")
                .fechaCreacion(LocalDate.now())
                .rol(Usuario.RolUsuario.SOLICITANTE)
                .intentosFallidos(0)
                .build();

        // Guardar en BD
        Usuario usuarioGuardado = usuarioRepository.save(usuario);
        log.info("✅ [REGISTRO] Usuario registrado exitosamente: {} (ID: {})", email, usuarioGuardado.getId());

        return usuarioGuardado;
    }

    /**
     * Validar formato de email
     */
    private void validarEmail(String email) {
        if (email == null || email.isBlank()) {
            throw new IllegalArgumentException("El email no puede estar vacío");
        }

        if (!email.contains("@") || !email.contains(".")) {
            throw new IllegalArgumentException("El email debe tener un formato válido");
        }

        if (email.length() > 255) {
            throw new IllegalArgumentException("El email no puede exceder 255 caracteres");
        }

        log.debug("✓ Email válido: {}", email);
    }

    /**
     * Validar contraseña
     */
    private void validarPassword(String password) {
        if (password == null || password.isBlank()) {
            throw new IllegalArgumentException("La contraseña no puede estar vacía");
        }

        if (password.length() < 6) {
            throw new IllegalArgumentException("La contraseña debe tener al menos 6 caracteres");
        }

        if (password.length() > 255) {
            throw new IllegalArgumentException("La contraseña no puede exceder 255 caracteres");
        }

        log.debug("✓ Contraseña válida (longitud: {})", password.length());
    }

    /**
     * Validar nombre
     */
    private void validarNombre(String nombre) {
        if (nombre == null || nombre.isBlank()) {
            throw new IllegalArgumentException("El nombre no puede estar vacío");
        }

        if (nombre.length() < 2) {
            throw new IllegalArgumentException("El nombre debe tener al menos 2 caracteres");
        }

        if (nombre.length() > 100) {
            throw new IllegalArgumentException("El nombre no puede exceder 100 caracteres");
        }

        log.debug("✓ Nombre válido: {}", nombre);
    }

    /**
     * Verificar si un email ya existe
     */
    public boolean existeEmail(String email) {
        return usuarioRepository.existsByEmail(email);
    }

    /**
     * Obtener usuario por email
     */
    public Usuario obtenerPorEmail(String email) {
        return usuarioRepository.findByEmail(email)
                .orElseThrow(() -> new IllegalArgumentException("Usuario no encontrado: " + email));
    }

    /**
     * Obtener usuario por ID
     */
    public Usuario obtenerPorId(Long id) {
        return usuarioRepository.findById(id)
                .orElseThrow(() -> new IllegalArgumentException("Usuario no encontrado: ID " + id));
    }

    /**
     * Contar total de usuarios
     */
    public long contarUsuarios() {
        return usuarioRepository.count();
    }

    /**
     * Iniciar sesión con email y contraseña
     *
     * @param email Email del usuario
     * @param password Contraseña
     * @return Usuario autenticado
     * @throws IllegalArgumentException si credenciales son inválidas
     */
    public Usuario iniciarSesion(String email, String password) {
        log.info(" [LOGIN] Intento de sesión con email: {}", email);

        // Validaciones de entrada
        validarCredencialesLogin(email, password);

        // Buscar usuario por email
        Usuario usuario = obtenerUsuarioParaLogin(email);

        // Validar credenciales
        validarContraseña(usuario, password);

        // Validar estado del usuario
        validarEstadoUsuario(usuario);

        // Registrar login exitoso
        registrarLoginExitoso(usuario);

        log.info("✅ [LOGIN] Sesión iniciada exitosamente para: {}", email);
        return usuario;
    }

    /**
     * Validar credenciales de entrada para login
     */
    private void validarCredencialesLogin(String email, String password) {
        if (email == null || email.isBlank()) {
            log.warn("⚠️ [LOGIN] Email vacío en intento de login");
            throw new IllegalArgumentException("El email no puede estar vacío");
        }

        if (password == null || password.isBlank()) {
            log.warn("⚠️ [LOGIN] Contraseña vacía en intento de login");
            throw new IllegalArgumentException("La contraseña no puede estar vacía");
        }

        log.debug("✓ Credenciales de entrada válidas");
    }

    /**
     * Obtener usuario para login por email
     */
    private Usuario obtenerUsuarioParaLogin(String email) {
        return usuarioRepository.findByEmail(email)
                .orElseThrow(() -> {
                    log.warn("⚠️ [LOGIN] Usuario no encontrado: {}", email);
                    return new IllegalArgumentException("Usuario no encontrado");
                });
    }

    /**
     * Validar contraseña del usuario
     */
    private void validarContraseña(Usuario usuario, String password) {
        if (!usuario.getPassword().equals(password)) {
            log.warn("⚠️ [LOGIN] Contraseña incorrecta para: {}", usuario.getEmail());

            // Incrementar intentos fallidos
            usuario.incrementarIntentosFallidos();
            usuarioRepository.save(usuario);

            log.warn("⚠️ [LOGIN] Intentos fallidos: {}/3", usuario.getIntentosFallidos());

            throw new IllegalArgumentException("Contraseña incorrecta");
        }

        log.debug("✓ Contraseña válida para: {}", usuario.getEmail());
    }

    /**
     * Validar estado del usuario para login
     */
    private void validarEstadoUsuario(Usuario usuario) {
        if (!usuario.esActivo()) {
            log.warn("⚠️ [LOGIN] Usuario inactivo o bloqueado: {} (Estado: {})",
                    usuario.getEmail(), usuario.getEstado());
            throw new IllegalArgumentException("Usuario inactivo o bloqueado");
        }

        log.debug("✓ Usuario activo: {}", usuario.getEmail());
    }

    /**
     * Registrar login exitoso
     */
    private void registrarLoginExitoso(Usuario usuario) {
        // Resetear intentos fallidos
        usuario.reiniciarIntentosFallidos();

        // Registrar fecha y hora de login
        usuario.registrarUltimoLogin();

        // Guardar cambios
        usuarioRepository.save(usuario);

        log.info("✅ [LOGIN] Login registrado para: {} en: {}",
                usuario.getEmail(), usuario.getFechaUltimoLogin());
    }
}

package com.example.gr01_1bt3_622_26a.service;

import com.example.gr01_1bt3_622_26a.entity.Usuario;
import com.example.gr01_1bt3_622_26a.repository.UsuarioRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import java.time.LocalDate;

/**
 *  REFACTOR: UsuarioService MEJORADO
 *
 * Ciclo TDD:
 *  RED: Test falla (no existe UsuarioService)
 *  GREEN: Se crea UsuarioService mínimo
 *  REFACTOR: Se mejora con validaciones, excepciones, logging
 *
 * Responsabilidades:
 * - Registrar nuevos usuarios
 * - Validar datos de entrada
 * - Manejo de excepciones
 * - Logging de eventos
 */
@Service
@RequiredArgsConstructor
@Slf4j
public class UsuarioService {

    private final UsuarioRepository usuarioRepository;

    /**
     * Registrar un nuevo usuario en la base de datos
     *
     * @param email Email del usuario
     * @param password Contraseña
     * @param nombre Nombre completo
     * @return Usuario registrado con ID asignado
     * @throws IllegalArgumentException si email ya existe o datos inválidos
     */
    public Usuario registrarUsuario(String email, String password, String nombre) {
        log.info(" [REGISTRO] Iniciando registro de usuario: {}", email);

        // Validaciones
        validarEmail(email);
        validarPassword(password);
        validarNombre(nombre);

        // Verificar que el email no exista
        if (usuarioRepository.existsByEmail(email)) {
            log.warn("⚠️ [REGISTRO] Email ya registrado: {}", email);
            throw new IllegalArgumentException("El email " + email + " ya está registrado");
        }

        // Crear usuario
        Usuario usuario = Usuario.builder()
                .email(email)
                .password(password) //  REFACTOR: En producción encriptar con BCrypt
                .nombre(nombre)
                .estado("ACTIVO")
                .fechaCreacion(LocalDate.now())
                .rol(Usuario.RolUsuario.SOLICITANTE)
                .intentosFallidos(0)
                .build();

        // Guardar en BD
        Usuario usuarioGuardado = usuarioRepository.save(usuario);
        log.info("✅ [REGISTRO] Usuario registrado exitosamente: {} (ID: {})", email, usuarioGuardado.getId());

        return usuarioGuardado;
    }

    /**
     * Validar formato de email
     */
    private void validarEmail(String email) {
        if (email == null || email.isBlank()) {
            throw new IllegalArgumentException("El email no puede estar vacío");
        }

        if (!email.contains("@") || !email.contains(".")) {
            throw new IllegalArgumentException("El email debe tener un formato válido");
        }

        if (email.length() > 255) {
            throw new IllegalArgumentException("El email no puede exceder 255 caracteres");
        }

        log.debug("✓ Email válido: {}", email);
    }

    /**
     * Validar contraseña
     */
    private void validarPassword(String password) {
        if (password == null || password.isBlank()) {
            throw new IllegalArgumentException("La contraseña no puede estar vacía");
        }

        if (password.length() < 6) {
            throw new IllegalArgumentException("La contraseña debe tener al menos 6 caracteres");
        }

        if (password.length() > 255) {
            throw new IllegalArgumentException("La contraseña no puede exceder 255 caracteres");
        }

        log.debug("✓ Contraseña válida (longitud: {})", password.length());
    }

    /**
     * Validar nombre
     */
    private void validarNombre(String nombre) {
        if (nombre == null || nombre.isBlank()) {
            throw new IllegalArgumentException("El nombre no puede estar vacío");
        }

        if (nombre.length() < 2) {
            throw new IllegalArgumentException("El nombre debe tener al menos 2 caracteres");
        }

        if (nombre.length() > 100) {
            throw new IllegalArgumentException("El nombre no puede exceder 100 caracteres");
        }

        log.debug("✓ Nombre válido: {}", nombre);
    }

    /**
     * Verificar si un email ya existe
     */
    public boolean existeEmail(String email) {
        return usuarioRepository.existsByEmail(email);
    }

    /**
     * Obtener usuario por email
     */
    public Usuario obtenerPorEmail(String email) {
        return usuarioRepository.findByEmail(email)
                .orElseThrow(() -> new IllegalArgumentException("Usuario no encontrado: " + email));
    }

    /**
     * Obtener usuario por ID
     */
    public Usuario obtenerPorId(Long id) {
        return usuarioRepository.findById(id)
                .orElseThrow(() -> new IllegalArgumentException("Usuario no encontrado: ID " + id));
    }

    /**
     * Contar total de usuarios
     */
    public long contarUsuarios() {
        return usuarioRepository.count();
    }

    /**
     * Iniciar sesión con email y contraseña
     *
     * @param email Email del usuario
     * @param password Contraseña
     * @return Usuario autenticado
     * @throws IllegalArgumentException si credenciales son inválidas
     */
    public Usuario iniciarSesion(String email, String password) {
        log.info(" [LOGIN] Intento de sesión con email: {}", email);

        // Validaciones de entrada
        validarCredencialesLogin(email, password);

        // Buscar usuario por email
        Usuario usuario = obtenerUsuarioParaLogin(email);

        // Validar credenciales
        validarContraseña(usuario, password);

        // Validar estado del usuario
        validarEstadoUsuario(usuario);

        // Registrar login exitoso
        registrarLoginExitoso(usuario);

        log.info("✅ [LOGIN] Sesión iniciada exitosamente para: {}", email);
        return usuario;
    }

    /**
     * Validar credenciales de entrada para login
     */
    private void validarCredencialesLogin(String email, String password) {
        if (email == null || email.isBlank()) {
            log.warn("⚠️ [LOGIN] Email vacío en intento de login");
            throw new IllegalArgumentException("El email no puede estar vacío");
        }

        if (password == null || password.isBlank()) {
            log.warn("⚠️ [LOGIN] Contraseña vacía en intento de login");
            throw new IllegalArgumentException("La contraseña no puede estar vacía");
        }

        log.debug("✓ Credenciales de entrada válidas");
    }

    /**
     * Obtener usuario para login por email
     */
    private Usuario obtenerUsuarioParaLogin(String email) {
        return usuarioRepository.findByEmail(email)
                .orElseThrow(() -> {
                    log.warn("⚠️ [LOGIN] Usuario no encontrado: {}", email);
                    return new IllegalArgumentException("Usuario no encontrado");
                });
    }

    /**
     * Validar contraseña del usuario
     */
    private void validarContraseña(Usuario usuario, String password) {
        if (!usuario.getPassword().equals(password)) {
            log.warn("⚠️ [LOGIN] Contraseña incorrecta para: {}", usuario.getEmail());

            // Incrementar intentos fallidos
            usuario.incrementarIntentosFallidos();
            usuarioRepository.save(usuario);

            log.warn("⚠️ [LOGIN] Intentos fallidos: {}/3", usuario.getIntentosFallidos());

            throw new IllegalArgumentException("Contraseña incorrecta");
        }

        log.debug("✓ Contraseña válida para: {}", usuario.getEmail());
    }

    /**
     * Validar estado del usuario para login
     */
    private void validarEstadoUsuario(Usuario usuario) {
        if (!usuario.esActivo()) {
            log.warn("⚠️ [LOGIN] Usuario inactivo o bloqueado: {} (Estado: {})",
                    usuario.getEmail(), usuario.getEstado());
            throw new IllegalArgumentException("Usuario inactivo o bloqueado");
        }

        log.debug("✓ Usuario activo: {}", usuario.getEmail());
    }

    /**
     * Registrar login exitoso
     */
    private void registrarLoginExitoso(Usuario usuario) {
        // Resetear intentos fallidos
        usuario.reiniciarIntentosFallidos();

        // Registrar fecha y hora de login
        usuario.registrarUltimoLogin();

        // Guardar cambios
        usuarioRepository.save(usuario);

        log.info("✅ [LOGIN] Login registrado para: {} en: {}",
                usuario.getEmail(), usuario.getFechaUltimoLogin());
    }

    /**
     * Cerrar sesión del usuario
     *
     * @param usuarioId ID del usuario
     * @return true si la sesión se cerró exitosamente
     * @throws IllegalArgumentException si el usuario no existe
     */
    public boolean cerrarSesion(Long usuarioId) {
        log.info(" [LOGOUT] Cerrando sesión para usuario ID: {}", usuarioId);

        // Validar que el usuario exista
        Usuario usuario = usuarioRepository.findById(usuarioId)
                .orElseThrow(() -> new IllegalArgumentException("Usuario no encontrado"));

        // Limpiar información de sesión
        usuario.setFechaUltimoLogin(null);

        // Guardar cambios
        usuarioRepository.save(usuario);

        log.info("✅ [LOGOUT] Sesión cerrada exitosamente para usuario ID: {}", usuarioId);
        return true;
    }
}

package com.example.gr01_1bt3_622_26a.service;

import com.example.gr01_1bt3_622_26a.entity.Usuario;
import com.example.gr01_1bt3_622_26a.repository.UsuarioRepository;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.when;

/**
 * TDD - CICLOS COMPLETADOS
 *
 * TEST 1: ✅ Crear Usuario (COMPLETADO: RED → GREEN → REFACTOR)
 * TEST 2: ✅ Registrar Usuario en BD (COMPLETADO: RED → GREEN → REFACTOR)
 * TEST 3:  Iniciar Sesión (INICIANDO: RED PHASE)
 *
 * Caso de Uso: Autenticación de Usuarios
 * Descripción: Validar credenciales y permitir login
 */
@DisplayName("TDD - Ciclo Completo: Usuario (RED → GREEN → REFACTOR)")
@ExtendWith(MockitoExtension.class)
public class UsuarioServiceTest {

    @Mock
    private UsuarioRepository usuarioRepository;

    @InjectMocks
    private UsuarioService usuarioService;

    private UsuarioService usuarioService;

    /**
     * ✅ TC1: Crear Usuario Exitosamente (Ya implementado)
     */
    @Test
    @DisplayName("TC1: Crear Usuario Exitosamente")
    void testCrearUsuario() {
        // ARRANGE
        String email = "juan@example.com";
        String password = "password123";
        String nombre = "Juan Pérez";

        // ACT
        Usuario usuario = Usuario.builder()
                .email(email)
                .password(password)
                .nombre(nombre)
                .estado("ACTIVO")
                .build();

        // ASSERT
        assertNotNull(usuario, "El usuario no debe ser nulo");
        assertEquals(email, usuario.getEmail(), "El email debe coincidir");
        assertEquals(password, usuario.getPassword(), "La contraseña debe coincidir");
        assertEquals(nombre, usuario.getNombre(), "El nombre debe coincidir");
        assertEquals("ACTIVO", usuario.getEstado(), "El estado debe ser ACTIVO");
    }

    /**
     *  RED: TC2 - Registrar Usuario en BD
     *
     * Este test FALLA porque:
     * - No existe UsuarioService
     * - No existe método registrarUsuario()
     * - No existe UsuarioRepository
     */
    @Test
    @DisplayName("TC2: Registrar Usuario en BD Exitosamente")
    void testRegistrarUsuarioEnBD() {
        // ARRANGE - Preparar datos
        String email = "carlos@example.com";
        String password = "password456";
        String nombre = "Carlos López";

        Usuario usuarioAGuardar = Usuario.builder()
                .email(email)
                .password(password)
                .nombre(nombre)
                .estado("ACTIVO")
                .build();

        // Mock: Simular que el repositorio guarda y retorna con ID
        Usuario usuarioGuardado = Usuario.builder()
                .id(1L)
                .email(email)
                .password(password)
                .nombre(nombre)
                .estado("ACTIVO")
                .build();

        when(usuarioRepository.save(any(Usuario.class))).thenReturn(usuarioGuardado);

        // ACT - Registrar usuario
        usuarioService = new UsuarioService(usuarioRepository);
